import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import TopBar from '../components/layout/TopBar';
import BottomNav from '../components/layout/BottomNav';
import {
  Card, SectionHeader, Pill, Divider, Spinner, EmptyState,
  ProfileCircle, BookCover, StatusButton,
} from '../components/common';
import {
  getGyodoks, getBooks, getBookStatus, updateBookStatus,
  getWishlist, getFeed, addFeedItem,
} from '../supabase/db';
import {
  calcGyodokStatus, getMyStatusText, getMemberStatus,
  getBookCardState, calcDday, getNextCheckpoint,
} from '../utils/statusCalc';

export default function HomePage() {
  const { user } = useAuth();
  const navigate = useNavigate();

  const [activeGyodok,  setActiveGyodok]  = useState(null);
  const [books,         setBooks]         = useState([]);
  const [allStatuses,   setAllStatuses]   = useState({});
  const [participants,  setParticipants]  = useState([]);
  const [myStatus,      setMyStatus]      = useState(null);
  const [wishlist,      setWishlist]      = useState([]);
  const [feed,          setFeed]          = useState([]);
  const [loading,       setLoading]       = useState(true);

  // 현재 진행 중인 교독 + 관련 데이터 로드
  const loadData = useCallback(async () => {
    if (!user) return;
    try {
      const gyodoks = await getGyodoks(user.id);
      const active  = gyodoks.find(g => g.status === 'active');
      if (!active) { setLoading(false); return; }

      setActiveGyodok(active);

      // 책 + 상태 병렬 로드
      const booksData = await getBooks(active.id);
      setBooks(booksData);

      // 참여자 정보 (userId 배열 → 이름 매핑은 별도 로드 필요하지만
      // 여기선 gyodok.participantIds 기준으로 처리)
      setParticipants(active.participantIds || []);

      // 모든 책 × 모든 참여자 상태
      const statusMap = {};
      for (const book of booksData) {
        statusMap[book.id] = {};
        for (const pid of (active.participantIds || [])) {
          statusMap[book.id][pid] = await getBookStatus(active.id, book.id, pid);
        }
      }
      setAllStatuses(statusMap);

      // 내 현재 차수 책 상태
      const gyodokStatus = calcGyodokStatus(
        (active.participantIds || []).map(id => ({ id })),
        booksData, statusMap
      );
      const myCurrentBook = booksData.find(
        b => b.round === gyodokStatus.round &&
             b.exchangeOrder?.includes(user.id)
      );
      if (myCurrentBook) {
        setMyStatus(statusMap[myCurrentBook.id]?.[user.id] || null);
      }

      // 위시리스트, 피드
      const [wl, fd] = await Promise.all([
        getWishlist(user.id),
        getFeed(active.id),
      ]);
      setWishlist(wl);
      setFeed(fd);

    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => { loadData(); }, [loadData]);

  // 상태 버튼 클릭
  const handleStatusChange = async (field) => {
    if (!activeGyodok || !user) return;

    const gyodokStatus = calcGyodokStatus(
      (activeGyodok.participantIds || []).map(id => ({ id })),
      books, allStatuses
    );
    const myCurrentBook = books.find(
      b => b.round === gyodokStatus.round &&
           b.exchangeOrder?.includes(user.id)
    );
    if (!myCurrentBook) return;

    const current = allStatuses[myCurrentBook.id]?.[user.id] || {};
    const updated  = { ...current, [field]: !current[field] };

    // 발송 해제 시 도착도 해제
    if (field === 'isSent' && !updated.isSent) updated.isArrived = false;

    await updateBookStatus(activeGyodok.id, myCurrentBook.id, user.id, updated);

    // 피드 추가
    const feedTypes = { isRead: 'read', isSent: 'sent', isArrived: 'arrived' };
    if (updated[field]) {
      await addFeedItem({
        gyodokId: activeGyodok.id,
        userId: user.id, userName: user.name,
        type: feedTypes[field],
        bookTitle: myCurrentBook.title || '',
      });
    }

    setMyStatus(updated);
    setAllStatuses(prev => ({
      ...prev,
      [myCurrentBook.id]: { ...prev[myCurrentBook.id], [user.id]: updated },
    }));
  };

  // ===== 렌더 =====

  if (loading) return (
    <div className="page">
      <TopBar title="홈" />
      <Spinner />
      <BottomNav />
    </div>
  );

  const gyodokStatus = activeGyodok
    ? calcGyodokStatus(
        (activeGyodok.participantIds || []).map(id => ({ id })),
        books, allStatuses
      )
    : null;

  const checkpoint = activeGyodok ? getNextCheckpoint(activeGyodok.checkpoints) : null;
  const dday = checkpoint ? calcDday(checkpoint.date) : null;

  return (
    <div className="page">
      <TopBar title="홈" />

      <div className="page-content fade-in">

        {/* ── D-day 블록 ── */}
        {activeGyodok && (
          <div
            onClick={() => navigate(`/gyodok/${activeGyodok.id}`)}
            style={{
              background: 'linear-gradient(135deg, #ccd5ae 0%, #faedcd 60%, #fefae0 100%)',
              borderRadius: 'var(--radius-lg)',
              padding: '12px 14px',
              marginBottom: 10,
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              cursor: 'pointer',
            }}
          >
            <div>
              <div style={{ fontSize: 10, color: '#5a6030', lineHeight: 1.8 }}>
                {activeGyodok.title}
              </div>
              <div style={{ fontSize: 28, fontWeight: 500, color: '#3a4028', lineHeight: 1.1 }}>
                {dday || 'D-?'}
              </div>
              {checkpoint && (
                <div style={{ fontSize: 10, color: '#5a6030', lineHeight: 1.8 }}>
                  ~ {formatDate(checkpoint.date)}<br />
                  <span style={{ color: '#3a4028', fontWeight: 500 }}>
                    {checkpoint.label}
                  </span>
                </div>
              )}
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 4, alignItems: 'flex-end' }}>
              <Pill variant="green">진행 중</Pill>
              {gyodokStatus && (
                <div style={{ fontSize: 10, color: '#3a4028', fontWeight: 500, marginTop: 2 }}>
                  {gyodokStatus.statusText}
                </div>
              )}
            </div>
          </div>
        )}

        {/* 진행 중인 교독 없을 때 */}
        {!activeGyodok && (
          <Card>
            <EmptyState
              message="진행 중인 교독이 없습니다"
              sub="관리자가 교독 모임을 생성하면 여기에 표시됩니다"
            />
          </Card>
        )}

        {/* ── 내 현재 상태 ── */}
        {activeGyodok && gyodokStatus && (
          <Card>
            <div style={{
              display: 'flex', alignItems: 'center',
              justifyContent: 'space-between', marginBottom: 10,
            }}>
              <div style={{ fontSize: 13, fontWeight: 500, color: 'var(--text-primary)' }}>
                내 현재 상태
              </div>
              <div style={{ fontSize: 11, color: 'var(--accent-primary)', fontWeight: 500 }}>
                {getMyStatusText(gyodokStatus.round, myStatus)}
              </div>
            </div>

            {/* 책 행 */}
            <MyBooksRow
              books={books}
              currentRound={gyodokStatus.round}
              userId={user.id}
            />

            {/* 상태 버튼 */}
            <div style={{ display: 'flex', gap: 6, marginTop: 8 }}>
              <StatusButton
                label="다 읽었어요!"
                active={!!myStatus?.isRead}
                onClick={() => handleStatusChange('isRead')}
              />
              <StatusButton
                label="발송했어요!"
                active={!!myStatus?.isSent}
                onClick={() => handleStatusChange('isSent')}
              />
            </div>
            <div style={{ display: 'flex', gap: 6, marginTop: 6 }}>
              <StatusButton
                label="도착했어요!"
                active={!!myStatus?.isArrived}
                disabled={!myStatus?.isSent}
                onClick={() => handleStatusChange('isArrived')}
              />
            </div>
            {!myStatus?.isSent && (
              <div style={{ fontSize: 10, color: 'var(--text-hint)', textAlign: 'center', marginTop: 4 }}>
                발송 완료 후 활성화됩니다
              </div>
            )}
          </Card>
        )}

        {/* ── 모임 현황 ── */}
        {activeGyodok && gyodokStatus && participants.length > 0 && (
          <Card>
            <div style={{ fontSize: 13, fontWeight: 500, color: 'var(--text-primary)', marginBottom: 10 }}>
              모임 현황
            </div>
            {participants.map((pid, idx) => (
              <MemberRow
                key={pid}
                userId={pid}
                books={books}
                currentRound={gyodokStatus.round}
                allStatuses={allStatuses}
                isMe={pid === user.id}
                isLast={idx === participants.length - 1}
              />
            ))}
          </Card>
        )}

        {/* ── 최근 업데이트 ── */}
        {feed.length > 0 && (
          <>
            <SectionHeader>최근 업데이트</SectionHeader>
            <Card style={{ padding: '8px 12px' }}>
              {feed.slice(0, 5).map(item => (
                <FeedItem key={item.id} item={item} />
              ))}
            </Card>
          </>
        )}

        {/* ── 위시리스트 ── */}
        {wishlist.length > 0 && (
          <>
            <SectionHeader>내 다음 책 후보</SectionHeader>
            <Card style={{ padding: '8px 12px' }}>
              {wishlist.map((item, idx) => (
                <WishItem key={item.id} item={item} isLast={idx === wishlist.length - 1} />
              ))}
              <div style={{ fontSize: 10, color: 'var(--text-hint)', textAlign: 'right', marginTop: 6 }}>
                최신 5개 표시
              </div>
            </Card>
          </>
        )}

        <div style={{ height: 16 }} />
      </div>

      <BottomNav />
    </div>
  );
}

/* ── 서브 컴포넌트 ── */

function MyBooksRow({ books, currentRound, userId }) {
  const totalRounds = 3;
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
      <ProfileCircle name="나" isMe size={32} />
      <div style={{ display: 'flex', gap: 8, flex: 1 }}>
        {Array.from({ length: totalRounds }, (_, i) => {
          const round = i + 1;
          const book  = books.find(b => b.round === round && b.exchangeOrder?.includes(userId));
          const state = getBookCardState(round, currentRound);
          return (
            <div key={round} style={{ flex: 1 }}>
              <BookCover
                coverUrl={book?.coverUrl}
                state={state}
                width="100%"
                height={60}
                style={{ width: '100%' }}
              />
            </div>
          );
        })}
      </div>
    </div>
  );
}

function MemberRow({ userId, books, currentRound, allStatuses, isMe, isLast }) {
  const totalRounds = 3;

  // 현재 차수 책 상태
  const currentBook = books.find(b => b.round === currentRound && b.exchangeOrder?.includes(userId));
  const status = currentBook ? allStatuses[currentBook.id]?.[userId] : null;
  const { label, variant } = getMemberStatus(status);

  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 12,
      paddingBottom: isLast ? 0 : 9,
      marginBottom: isLast ? 0 : 9,
      borderBottom: isLast ? 'none' : '0.5px solid var(--border-default)',
    }}>
      <ProfileCircle name={userId} isMe={isMe} size={26} />
      <div style={{ display: 'flex', gap: 6, flex: 1 }}>
        {Array.from({ length: totalRounds }, (_, i) => {
          const round = i + 1;
          const book  = books.find(b => b.round === round && b.exchangeOrder?.includes(userId));
          const state = getBookCardState(round, currentRound);
          return (
            <div key={round} style={{ flex: 1 }}>
              <BookCover
                coverUrl={book?.coverUrl}
                state={state}
                width="100%"
                height={60}
                style={{ width: '100%' }}
              />
            </div>
          );
        })}
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 4, flexShrink: 0 }}>
        <div style={{
          width: 6, height: 6, borderRadius: '50%',
          background: variant === 'green' ? 'var(--accent-green)' : 'var(--status-pending)',
          border: variant !== 'green' ? '0.5px solid var(--border-strong)' : 'none',
        }} />
        <span style={{ fontSize: 10, color: 'var(--text-secondary)' }}>{label}</span>
      </div>
    </div>
  );
}

function FeedItem({ item }) {
  const typeLabels = {
    read:       '를 완독했어요',
    sent:       '를 발송했어요',
    arrived:    '이 도착했어요',
    registered: '을 등록했어요',
  };
  const suffix = typeLabels[item.type] || '';

  return (
    <div style={{
      display: 'flex', alignItems: 'flex-start', gap: 8,
      padding: '6px 0',
      borderBottom: '0.5px solid var(--border-default)',
    }}>
      <div style={{
        width: 22, height: 22, borderRadius: '50%',
        background: 'var(--bg-surface-secondary)',
        flexShrink: 0,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontSize: 10, color: 'var(--text-tertiary)',
      }}>
        {item.userName?.charAt(0)}
      </div>
      <div style={{ fontSize: 11, color: 'var(--text-secondary)', lineHeight: 1.5 }}>
        <span style={{ fontWeight: 500, color: 'var(--text-primary)' }}>{item.userName}</span>
        님이 《{item.bookTitle}》{suffix}
      </div>
    </div>
  );
}

function WishItem({ item, isLast }) {
  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 8,
      padding: '5px 0',
      borderBottom: isLast ? 'none' : '0.5px solid var(--border-default)',
    }}>
      <div style={{
        width: 26, height: 36, borderRadius: 3,
        background: item.coverUrl ? 'transparent' : 'var(--accent-amber)',
        flexShrink: 0, overflow: 'hidden',
      }}>
        {item.coverUrl && (
          <img src={item.coverUrl} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        )}
      </div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
        <div style={{ fontSize: 12, fontWeight: 500, color: 'var(--text-primary)' }}>{item.title}</div>
        <div style={{ fontSize: 10, color: 'var(--text-secondary)' }}>{item.author}</div>
        <div style={{ fontSize: 10, color: 'var(--text-tertiary)' }}>{item.publisher}</div>
      </div>
    </div>
  );
}

function formatDate(ts) {
  if (!ts) return '';
  const d = ts.toDate ? ts.toDate() : new Date(ts);
  return `${d.getFullYear()}.${String(d.getMonth() + 1).padStart(2, '0')}.${String(d.getDate()).padStart(2, '0')}`;
}
